class Solution {
    public int minimizeXor(int num1, int num2) {
        int setBitsInNum2 = Integer.bitCount(num2);
        int result = 0;
        for (int i = 30; i >= 0; i--) {
            if ((num1 & (1 << i)) != 0 && setBitsInNum2 > 0) {
                result |= (1 << i);
                setBitsInNum2--;
            }
        }
        for (int i = 0; i <= 30; i++) {
            if ((num1 & (1 << i)) == 0 && setBitsInNum2 > 0) {
                result |= (1 << i);
                setBitsInNum2--;
            }
        }
        return result;
    }
}
